#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

__device__ void bpnn_layerforward_cuda(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  float *input_node,
					  float *weight_matrix,
					  int in,
					  int hid,
					  int by,
					  int tx,
					  int ty) 
{

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  

   int index_in = HEIGHT * by + ty + 1;

	if ( tx == 0 )
		input_node[ty] = input_cuda[index_in] ;
	__syncthreads();

	weight_matrix[ty * WIDTH + tx] =  input_hidden_cuda[index];
	__syncthreads();

	weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] * input_node[ty];
	__syncthreads();

	for ( int i = 1 ; i <= HEIGHT ; i=i*2){

      int power_two = i; 


	    if( ty % power_two == 0 )
		  weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2)* WIDTH + tx];

		__syncthreads();

    }

    input_hidden_cuda[index] =  weight_matrix[ty * WIDTH + tx];

	__syncthreads();

    if ( tx == 0 ) {
	  hidden_partial_sum[by * hid + ty] = weight_matrix[tx* WIDTH + ty];
    }

}

__global__ void 
bpnn_layerforward_ocl(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{
   int by = blockIdx.y;
   int tx = threadIdx.x;
   int ty = threadIdx.y;

   extern __shared__ float input_node[HEIGHT];
   extern __shared__ float weight_matrix[HEIGHT * WIDTH];

   bpnn_layerforward_cuda(input_cuda, output_hidden_cuda, input_hidden_cuda, hidden_partial_sum, input_node, weight_matrix, in, hid, by, tx, ty);
}

__device__ void bpnn_adjust_weights_cuda(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw,
										int by,
										int tx,
										int ty)
{

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
   int index_y = HEIGHT * by + ty + 1;
   int index_x = tx + 1;

   w[index] += ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
   oldw[index] = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));

   __syncthreads();

   if (ty == 0 && by ==0){
	w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
	oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
   }
}

__global__ void  bpnn_adjust_weights_ocl(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)
{
   int by = blockIdx.y;
   int tx = threadIdx.x;
   int ty = threadIdx.y;

   bpnn_adjust_weights_cuda(delta, hid, ly, in, w, oldw, by, tx, ty);
}

