__device__ void horizontalStep(TransformBuffer *buffer, const int count, const int prevOffset, const int midOffset, const int nextOffset, int flag) {
    const int STEPS = count / buffer->SIZE_X;
    const int finalCount = count % buffer->SIZE_X;
    const int finalOffset = count - finalCount;
    int tid = threadIdx.x;

    for (int i = 0; i < STEPS; i++) {
        const int previous = buffer->data[prevOffset + i * buffer->SIZE_X + tid];
        const int next = buffer->data[nextOffset + i * buffer->SIZE_X + tid];
        int *center = &(buffer->data[midOffset + i * buffer->SIZE_X + tid]);
        if (flag == 0) {
            *center -= (previous + next) / 2;
        } else if (flag == 1) {
            *center += (previous + next + 2) / 4;
        }
    }

    if (tid < finalCount) {
        const int previous = buffer->data[prevOffset + finalOffset + tid];
        const int next = buffer->data[nextOffset + finalOffset + tid];
        int *center = &(buffer->data[midOffset + finalOffset + tid]);

        if (flag == 0) {
            *center -= (previous + next) / 2;
        } else if (flag == 1) {
            *center += (previous + next + 2) / 4;
        }
    }
}

__device__ void forEachHorizontalOdd(TransformBuffer *buffer, const int firstLine, const int numLines, int flag) {
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE;
    const int centerOffset = prevOffset + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;

    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}

__device__ void forEachHorizontalEven(TransformBuffer *buffer, const int firstLine, const int numLines, int flag) {
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int centerOffset = firstLine * buffer->VERTICAL_STRIDE + 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;

    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}

__device__ void forEachVerticalOdd(TransformBuffer *buffer, const int columnOffset, int flag) {
    int steps = (buffer->SIZE_Y - 1) / 2;
    for (int i = 0; i < steps; i++) {
        int row = i * 2 + 1;
        int prev = buffer->data[columnOffset + (row - 1) * buffer->VERTICAL_STRIDE];
        int next = buffer->data[columnOffset + (row + 1) * buffer->VERTICAL_STRIDE];

        if (flag == 0) {
