            writeLinearCUDA(cl_c_b_out, d->pixWidth, d->pixHeight, d->outFilename, ".b");
        }
#endif

#ifdef TIMING
        gettimeofday(&tv_close_start, NULL);
#endif
        cudaFree(cl_c_r);
        cudaFree(cl_c_g);
        cudaFree(cl_c_b);
        cudaFree(cl_c_g_out);
        cudaFree(cl_c_b_out);
    } else if (d->components == 1) {
#ifdef TIMING
        gettimeofday(&tv_mem_alloc_start, NULL);
#endif
        int *cl_c_r;
        cudaMalloc(&cl_c_r, componentSize);
#ifdef TIMING
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

        bwToComponentCUDA(cl_c_r, d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWTCUDA(cl_c_r, cl_c_r_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

