void histogramInit(int listsize) {
    cudaUint num = 0;
    cudaGetPlatformIDs(0, NULL, &num);
    cudaPlatformID platformID[num];
    cudaGetPlatformIDs(num, platformID, NULL);

    cudaGetDeviceIDs(platformID[platform_id_inuse],CUDA_DEVICE_TYPE_ALL,0,NULL,&num);

    char name[128];
    cudaGetPlatformInfo(platformID[platform_id_inuse], CUDA_PLATFORM_PROFILE,128,name,NULL);


    cudaDeviceID devices[num];
    err = cudaGetDeviceIDs(platformID[platform_id_inuse],CUDA_DEVICE_TYPE_ALL,num,devices,NULL);



    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to create a device group! (HistogramInit)\n");
        exit(1);
    }

    cudaGetDeviceInfo(devices[device_id_inuse],CUDA_DEVICE_NAME,128,name,NULL);

    printf("%s \n", name);

    cudaContextProperties contextProperties[] =
    {
        CUDA_CONTEXT_PLATFORM,
        (cudaContextProperties)platformID[platform_id_inuse],
        0
    };

    histoContext = cudaCreateContext(contextProperties, 1, &devices[device_id_inuse], NULL, NULL, &err);
    histoCommands = cudaCreateStream(histoContext, devices[device_id_inuse], CUDA_STREAM_PROFILING_ENABLE, &err);

    FILE *fp;
    const char fileName[]="./histogram1024.cu";
    size_t source_size;
    char *source_str;

    fp = fopen(fileName, "r");
	if (!fp) {
		fprintf(stderr, "Failed to load kernel.\n");
		exit(1);
	}


	source_str = (char *)malloc(MAX_SOURCE_SIZE);
	source_size = fread(source_str, 1, MAX_SOURCE_SIZE, fp);
    source_str[source_size] = '\0';
	fclose(fp);

    histoProgram = cudaCreateProgramWithSource(histoContext, 1, (const char **) &source_str, (const size_t *)&source_size, &err);
    if (!histoProgram)
    {
        printf("Error: Failed to create compute program! %d\n", err);
        exit(1);
    }
    free(source_str);

    err = cudaBuildProgram(histoProgram, 0, NULL, NULL, NULL, NULL);
    if (err != CUDA_SUCCESS)
    {
        size_t len;
        char buffer[2048];

        printf("Error: Failed to build program executable!\n");
        cudaGetProgramBuildInfo(histoProgram, devices[0], CUDA_PROGRAM_BUILD_LOG, sizeof(buffer), buffer, &len);
        printf("%s\n", buffer);
        exit(1);
    }

    histoKernel = cudaCreateKernel(histoProgram, "histogram1024Kernel", &err);
    if (!histoKernel || err != CUDA_SUCCESS)
    {
        printf("Error: Failed to create compute kernel!\n");
        exit(1);
    }

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_init_start, &tv);
	init_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    histoInput = cudaCreateBuffer(histoContext,  CUDA_MEM_READ_ONLY,  listsize*(sizeof(float)), NULL, NULL);
    histoOutput = cudaCreateBuffer(histoContext, CUDA_MEM_READ_WRITE, 1024 * sizeof(unsigned int), NULL, NULL);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
}

void histogram1024GPU(unsigned int *h_Result, float *d_Data, float minimum, float maximum,int listsize){
    cudaEvent write_event[2];
    err = cudaEnqueueWriteBuffer(histoCommands, histoInput, CUDA_TRUE, 0, listsize*sizeof(float), d_Data, 0, NULL, &write_event[0]);
    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to write to source array!\n");
        exit(1);
    }
    err = cudaEnqueueWriteBuffer(histoCommands, histoOutput, CUDA_TRUE, 0, DIVISIONS*sizeof(unsigned int), h_Result, 0, NULL, &write_event[1]);
    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to write to source array!\n");
        exit(1);
    }
    err = 0;
    err  = cudaSetKernelArg(histoKernel, 0, sizeof(cudaMemoryHandle), &histoOutput);
    err  = cudaSetKernelArg(histoKernel, 1, sizeof(cudaMemoryHandle), &histoInput);
    err  = cudaSetKernelArg(histoKernel, 2, sizeof(float), &minimum);
    err  = cudaSetKernelArg(histoKernel, 3, sizeof(float), &maximum);
    err  = cudaSetKernelArg(histoKernel, 4, sizeof(int), &listsize);

    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to set kernel arguments! %d\n", err);
        exit(1);
    }

    size_t global = 6144;
    size_t local;
#ifdef HISTO_WG_SIZE_0
    local = HISTO_WG_SIZE_0;
#else
    local = 96;
#endif
    err = cudaEnqueueNDRangeKernel(histoCommands, histoKernel, 1, NULL, &global, &local, 0, NULL, &histoEvent);
    if (err)
    {
        printf("Error: Failed to execute histogram kernel!\n");
        exit(1);
    }
    cudaWaitForEvents(1 , &histoEvent);
    cudaFinish(histoCommands);
#ifdef TIMING
    h2d_time += probe_event_time(write_event[0], histoCommands);
    h2d_time += probe_event_time(write_event[1], histoCommands);
    kernel_time += probe_event_time(histoEvent, histoCommands);
#endif
    cudaReleaseEvent(write_event[0]);
    cudaReleaseEvent(write_event[1]);

    cudaEvent read_event;
    err = cudaEnqueueReadBuffer( histoCommands, histoOutput, CUDA_TRUE, 0, 1024 * sizeof(unsigned int), h_Result, 0, NULL, &read_event);
    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to read histo output array! %d\n", err);
        exit(1);
    }
    cudaFinish(histoCommands);
#ifdef TIMING
    d2h_time += probe_event_time(read_event, histoCommands);
#endif
    cudaReleaseEvent(read_event);

    cudaUlong time_start, time_end;
    double total_time;
    cudaGetEventProfilingInfo(histoEvent, CUDA_PROFILING_COMMAND_START, sizeof(time_start), &time_start, NULL);
    cudaGetEventProfilingInfo(histoEvent, CUDA_PROFILING_COMMAND_END, sizeof(time_end), &time_end, NULL);
    total_time = time_end - time_start;
    sum+= total_time/1000000.0;
    printf("Histogram Kernel Time: %0.3f \n", total_time/1000000);
}

void finish_histogram() {
    cudaReleaseProgram(histoProgram);
    cudaReleaseKernel(histoKernel);
    cudaReleaseStream(histoCommands);
    cudaReleaseContext(histoContext);
    cudaReleaseMemObject((histoInput));
    cudaReleaseMemObject((histoOutput));
}




