			piv = l_pivotpoints[idx]; 
			jump /= 2;
		}
		idx = (elem < piv) ? idx : (idx + 1);

		indice[tid] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;  
