#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>
#include <omp.h>
#include "kmeans.h"

float	min_rmse_ref = FLT_MAX;		
extern double wtime(void);

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

#ifndef BLOCK_SIZE2
#define BLOCK_SIZE2 256
#endif

// Global CUDA variables
float *d_feature;
float *d_feature_swap;
float *d_cluster;
int *d_membership;
int *membership_OCL;

static int cuda_initialized = 0;

static int initialize_cuda()
{
    if (cuda_initialized) return 0;

    // Check for device
    int device_count = 0;
    if (cudaGetDeviceCount(&device_count) != cudaSuccess || device_count == 0) {
        printf("ERROR: No CUDA devices found\n");
        return -1;
    }

    cuda_initialized = 1;
    return 0;
}

int allocate(int n_points, int n_features, int n_clusters, float **feature)
{
    cudaError_t err;

    if (initialize_cuda()) return -1;

    // Allocate device memory
    err = cudaMalloc(&d_feature, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature => %d\n", err); return -1;}

    err = cudaMalloc(&d_feature_swap, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature_swap => %d\n", err); return -1;}

    err = cudaMalloc(&d_cluster, n_clusters * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_cluster => %d\n", err); return -1;}

    err = cudaMalloc(&d_membership, n_points * sizeof(int));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_membership => %d\n", err); return -1;}

    // Copy feature data to device
    err = cudaMemcpy(d_feature, feature[0], n_points * n_features * sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_feature => %d\n", err); return -1; }

    // Launch swap kernel to transpose features
    dim3 block(BLOCK_SIZE);
    dim3 grid((n_points + BLOCK_SIZE - 1) / BLOCK_SIZE);

    kmeans_swap(d_feature, d_feature_swap, n_points, n_features);
    cudaDeviceSynchronize();

    membership_OCL = (int*) malloc(n_points * sizeof(int));
    if (!membership_OCL) { printf("ERROR: malloc membership_OCL failed\n"); return -1; }

    return 0;
}

void deallocateMemory()
{
    if (d_feature) cudaFree(d_feature);
    if (d_feature_swap) cudaFree(d_feature_swap);
    if (d_cluster) cudaFree(d_cluster);
    if (d_membership) cudaFree(d_membership);
    if (membership_OCL) free(membership_OCL);

    d_feature = NULL;
    d_feature_swap = NULL;
    d_cluster = NULL;
    d_membership = NULL;
    membership_OCL = NULL;
    cuda_initialized = 0;
}


int main( int argc, char** argv) 
{
    printf("WG size of kernel_swap = %d, WG size of kernel_kmeans = %d \n", BLOCK_SIZE, BLOCK_SIZE2);

    setup(argc, argv);

    // No explicit shutdown needed as deallocateMemory is called in cluster loop
    return 0;
}

int	kmeansOCL(float **feature,    
           int     n_features,
           int     n_points,
           int     n_clusters,
           int    *membership,
		   float **clusters,
		   int     *new_centers_len,
           float  **new_centers)	
{

	int delta = 0;
	int i, j, k;
	cudaError_t err;

    // Copy cluster data to device
    err = cudaMemcpy(d_cluster, clusters[0], n_clusters * n_features * sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_cluster => %d\n", err); return -1; }

    int size = 0; int offset = 0;

    dim3 block(BLOCK_SIZE2);
    dim3 grid((n_points + BLOCK_SIZE2 - 1) / BLOCK_SIZE2);

    kmeans_kernel_c(d_feature_swap, d_cluster, d_membership, n_points, n_clusters, n_features, offset, size);
    cudaDeviceSynchronize();

    // Read membership back to host
    err = cudaMemcpy(membership_OCL, d_membership, n_points * sizeof(int), cudaMemcpyDeviceToHost);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy membership => %d\n", err); return -1; }

	delta = 0;
	for (i = 0; i < n_points; i++)
	{
		int cluster_id = membership_OCL[i];
		new_centers_len[cluster_id]++;
		if (membership_OCL[i] != membership[i])
		{
			delta++;
			membership[i] = membership_OCL[i];
		}
		for (j = 0; j < n_features; j++)
		{
			new_centers[cluster_id][j] += feature[i][j];
		}
	}

	return delta;
}

