#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__global__ void 
lud_diagonal(float *m, 
             float *shadow,
             int   matrix_dim, 
             int   offset)
{ 
    int i, j;
    int tx = threadIdx.x;

    int array_offset = offset * matrix_dim + offset;
    for(i = 0; i < BLOCK_SIZE; i++){
        shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
        array_offset += matrix_dim;
    }

    __syncthreads();

    for(i = 0; i < BLOCK_SIZE - 1; i++) {

        if (tx > i){
            for(j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        __syncthreads();
        if (tx > i){
            for(j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }

        __syncthreads();
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for(i = 1; i < BLOCK_SIZE; i++){
        m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
        array_offset += matrix_dim;
    }

}

__global__ void
lud_perimeter(float *m, 
              float *dia,
              float *peri_row,
              float *peri_col,
              int matrix_dim, 
              int offset)
{
    int i, j, array_offset;
    int idx;

    int bx = blockIdx.x;	
    int tx = threadIdx.x;

    if (tx < BLOCK_SIZE) {
        idx = tx;
        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE / 2; i++){
            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }

    } else {
        idx = tx - BLOCK_SIZE;

        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++){
            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }
    }
    __syncthreads();

    if (tx < BLOCK_SIZE) { 
        idx = tx;
        for(i = 1; i < BLOCK_SIZE; i++){
            for (j = 0; j < i; j++)
                peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
        }
    } else { 
        idx = tx - BLOCK_SIZE;
        for(i = 0; i < BLOCK_SIZE; i++){
            for(j = 0; j < i; j++)
                peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

    __syncthreads();

    if (tx < BLOCK_SIZE) { 
        idx = tx;
        array_offset = (offset + 1) * matrix_dim + offset;
        for(i = 1; i < BLOCK_SIZE; i++){
            m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    } else { 
        idx = tx - BLOCK_SIZE;
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for(i = 0; i < BLOCK_SIZE; i++){
            m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }

}

__global__ void
lud_internal(float *m, 
             float *peri_row,
             float *peri_col,
             int matrix_dim, 
             int offset)
{

    int bx = blockIdx.x;	
    int by = blockIdx.y;	

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int i;
    float sum;

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];

    __syncthreads();

    sum = 0;
    for (i = 0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;

}

void lud_cuda(float *d_m, int matrix_dim);

void lud_cuda(float *d_m_host, int matrix_dim) {
    float *d_m;
    size_t size = matrix_dim * matrix_dim * sizeof(float);

    cudaMalloc(&d_m, size);
    cudaMemcpy(d_m, d_m_host, size, cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE);
    dim3 grid(1);

    for (int i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // lud_diagonal
        size_t shadow_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
        float *d_shadow;
        cudaMalloc(&d_shadow, shadow_size);

        dim3 diag_block(BLOCK_SIZE);
        dim3 diag_grid(1);

        lud_diagonal<<<diag_grid, diag_block>>>(d_m, d_shadow, matrix_dim, i);
        cudaFree(d_shadow);

        // lud_perimeter
        size_t local_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
        float *d_dia, *d_peri_row, *d_peri_col;
        cudaMalloc(&d_dia, local_size);
        cudaMalloc(&d_peri_row, local_size);
        cudaMalloc(&d_peri_col, local_size);

        int num_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
        if (num_blocks > 0) {
            dim3 peri_block(BLOCK_SIZE * 2);
            dim3 peri_grid(num_blocks);
            lud_perimeter<<<peri_grid, peri_block>>>(d_m, d_dia, d_peri_row, d_peri_col, matrix_dim, i);
        }
        cudaFree(d_dia);
        cudaFree(d_peri_row);
        cudaFree(d_peri_col);

        // lud_internal
        if (num_blocks > 0) {
            dim3 int_block(BLOCK_SIZE, BLOCK_SIZE);
            dim3 int_grid(num_blocks, num_blocks);
            size_t int_local_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
            float *d_int_row, *d_int_col;
            cudaMalloc(&d_int_row, int_local_size);
            cudaMalloc(&d_int_col, int_local_size);

            lud_internal<<<int_grid, int_block>>>(d_m, d_int_row, d_int_col, matrix_dim, i);
            cudaFree(d_int_row);
            cudaFree(d_int_col);
        }
    }

    // Final diagonal
    int i = matrix_dim - BLOCK_SIZE;
    size_t shadow_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);
    float *d_shadow;
    cudaMalloc(&d_shadow, shadow_size);
    dim3 diag_block(BLOCK_SIZE);
    dim3 diag_grid(1);
    lud_diagonal<<<diag_grid, diag_block>>>(d_m, d_shadow, matrix_dim, i);
    cudaFree(d_shadow);

    cudaMemcpy(d_m_host, d_m, size, cudaMemcpyDeviceToHost);
    cudaFree(d_m);
}

