    cudaMemcpy(com, d_com, d_com_mem, cudaMemcpyDeviceToHost);

    initvalu_offset_ecc = 0;
    initvalu_offset_Dyad = 46;
    initvalu_offset_SL = 61;
    initvalu_offset_Cyt = 76;

    kernel_fin(	initvalu,
                initvalu_offset_ecc,
                initvalu_offset_Dyad,
                initvalu_offset_SL,
                initvalu_offset_Cyt,
                parameter,
                finavalu,
                com[0],
                com[1],
                com[2]);

    for(i=0; i<EQUATIONS; i++){
        if (isnan(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
        else if (isinf(finavalu[i]) == 1){ 
            finavalu[i] = 0.0001;
        }
    }

}

#define max(x,y) ( (x) < (y) ? (y) : (x) )
#define min(x,y) ( (x) < (y) ? (x) : (y) )

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

int 
solver(fp **y,
        fp *x,
        int xmax,
        fp *params,
        fp *com,

        fp* d_initvalu,
        fp* d_finavalu,
        fp* d_params,
        fp* d_com)
{

    fp err_exponent;
    int error;
    int outside;
    fp h;
    fp h_init;
    fp tolerance;
    int xmin;

    fp scale_min;
    fp scale_fina;
    fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
    fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
    fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

    int i, j, k;

    err_exponent = 1.0 / 7.0;
    h_init = 1;
    h = h_init;
    xmin = 0;
    tolerance = 10 / (fp)(xmax-xmin);

    x[0] = 0;

    if (xmax < xmin || h <= 0.0){
        return -2;
    }

    if (xmax == xmin){
        return 0; 
    }

    if (h > (xmax - xmin) ) { 
        h = (fp)xmax - (fp)xmin; 
    }

    printf("Time Steps: ");
    fflush(0);

    for(k=1; k<=xmax; k++) {

        x[k] = k-1;
        h = h_init;

        scale_fina = 1.0;

        for (j = 0; j < ATTEMPTS; j++) {

            error = 0;
            outside = 0;
            scale_min = MAX_SCALE_FACTOR;

            embedded_fehlberg_7_8(	x[k],
                                    h,
                                    y[k-1],
                                    y[k],
                                    err,
                                    params,
                                    com,

                                    d_initvalu,
                                    d_finavalu,
                                    d_params,
                                    d_com);

            for(i=0; i<EQUATIONS; i++){
                if(err[i] > 0){
                    error = 1;
                }
            }
            if (error != 1) {
                scale_fina = MAX_SCALE_FACTOR; 
                break;
            }

            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0){
                    yy[i] = tolerance;
                }
                else{
                    yy[i] = fabs(y[k-1][i]);
                }
                scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
                if(scale[i]<scale_min){
                    scale_min = scale[i];
                }
            }
            scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

            for(i=0; i<EQUATIONS; i++){
                if ( err[i] > ( tolerance * yy[i] ) ){
                    outside = 1;
                }
            }
            if (outside == 0){
                break;
            }

            h = h * scale_fina;

            if (h >= 0.9) {
                h = 0.9;
            }

            if ( x[k] + h > (fp)xmax ){
                h = (fp)xmax - x[k];
            }

            else if ( x[k] + h + 0.5 * h > (fp)xmax ){
                h = 0.5 * h;
            }

        }

        x[k] = x[k] + h;

        if ( j >= ATTEMPTS ) {
            return -1; 
        }

        printf("%d ", k);
        fflush(0);

    }

    printf("\n");
    fflush(0);

    free(err);
    free(scale);
    free(yy);

    return 0;

}

int 
main(int argc, 
        char *argv []){

    int cur_arg;
    int xmax;
    int workload = 1;
    char *data_dir;

    if(argc>3){
        for(cur_arg=1; cur_arg<argc; cur_arg++){

            if(strcmp(argv[cur_arg], "-time")==0){

                if(argc>=cur_arg+1){

                    if(isInteger(argv[cur_arg+1])==1){
                        xmax = atoi(argv[cur_arg+1]);
                        if(xmax<0){
                            printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
                            return 0;
                        }
                        cur_arg = cur_arg+1;
                    }

                    else{
                        printf("RROR: Value to -time argument in not a number\n");
                        return 0;
                    }
                }

                else{
                    printf("ERROR: Missing value to -time argument\n");
                    return 0;
                }
            }
            else if(strcmp(argv[cur_arg], "-p")==0) {
                if(argc>=cur_arg+1)
                    if(isInteger(argv[cur_arg+1])==1) {
                        // platform_id_inuse logic removed as not needed for CUDA single device context in this simplified wrapper
                        cur_arg = cur_arg+1;
                    }
            }
            else if(strcmp(argv[cur_arg], "-d")==0) {
                if(argc>=cur_arg+1)
                    if(isInteger(argv[cur_arg+1])==1) {
                        // device_id_inuse logic removed as not needed for CUDA single device context in this simplified wrapper
                        cur_arg = cur_arg+1;
                    }
            }
            else if (strcmp(argv[cur_arg], "-r") == 0) {
                if (argc >= cur_arg+1) {
                    data_dir = argv[cur_arg+1];
                    cur_arg++;
                }
            }

            else{
                printf("ERROR: Unknown argument\n");
                return 0;
            }
        }

    }
    else{
        printf("Provide time argument, example: -time 100");
        return 0;
    }

    if(workload == 1){

        int i,j;

        long long memory;
        memory = workload*(xmax+1)*EQUATIONS*4;
        if(memory>1000000000){
            printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
            return 0;
        }

        fp*** y;
        y = (fp ***) malloc(workload* sizeof(fp **));
        for(i=0; i<workload; i++){
            y[i] = (fp**)malloc((1+xmax)*sizeof(fp*));
            for(j=0; j<(1+xmax); j++){
                y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp));
            }
        }

        fp** x;
        x = (fp **) malloc(workload * sizeof(fp *));
