                        0);
        }

        fp* d_initvalu;
        fp* d_finavalu;
        fp* d_params;
        fp* d_com;

        cudaMalloc(&d_initvalu, EQUATIONS * sizeof(fp));
        cudaMalloc(&d_finavalu, EQUATIONS * sizeof(fp));
        cudaMalloc(&d_params, PARAMETERS * sizeof(fp));
        cudaMalloc(&d_com, 3 * sizeof(fp));

        kernel_gpu_opencl_wrapper(	xmax,					
                                    workload,

                                    y,
                                    x,
                                    params,
                                    com);

        FILE * pFile;
        pFile = fopen ("output.txt","w");
        if (pFile==NULL)
        {
            fputs ("fopen example",pFile);
            return -1;
        }

        int k;
        for(i=0; i<workload; i++){
            fprintf(pFile, "WORKLOAD %d:\n", i);
            for(j=0; j<(xmax+1); j++){
                fprintf(pFile, "\tTIME %d:\n", j);
                for(k=0; k<EQUATIONS; k++){
                    fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
                }
            }
        }

        fclose (pFile);

        for (i= 0; i< workload; i++){
            for (j= 0; j< (1+xmax); j++){
                free(y[i][j]);
            }
            free(y[i]);
        }
        free(y);

        for (i= 0; i< workload; i++){
            free(x[i]);
        }
        free(x);

        for (i= 0; i< workload; i++){
            free(params[i]);
        }
        free(params);

        free(com);

        cudaFree(d_initvalu);
        cudaFree(d_finavalu);
        cudaFree(d_params);
        cudaFree(d_com);

    }

    return 0;

}

