				fp* d_dS, 
				fp* d_dE, 
				fp* d_dW, 
				fp* d_c, 
				fp* d_I){


    int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = bx*NUMBER_THREADS+tx;											
	int row;																
	int col;																


	fp d_cN,d_cS,d_cW,d_cE;
	fp d_D;


	row = (ei+1) % d_Nr - 1;												
	col = (ei+1) / d_Nr + 1 - 1;											
	if((ei+1) % d_Nr == 0){
		row = d_Nr - 1;
